def seed_content():
	for category, topics in TOPICS.items():
		for t in topics:
			if not frappe.db.exists('Content Topic', t):
				frappe.get_doc({'doctype': 'Content Topic', 'topic': t,
					'category': category, 'active': 1}).insert(ignore_permissions=True)
	for p in POSTS:
		exists = frappe.db.exists('Content Post',
			{'post_title': p['post_title'], 'platform': p['platform'], 'month': p['month']})
		if not exists:
			doc = frappe.get_doc(dict({'doctype': 'Content Post'}, **p))
			doc.insert(ignore_permissions=True)


def seed_marketing_template():
	name = 'Marketing Lead - Social Media Rhythm'
	if frappe.db.exists('Activity Template', name):
		return
	doc = frappe.get_doc({'doctype': 'Activity Template', 'template_name': name,
		'description': 'Recurring social-media activities from the 12-Month Social Media Strategy.'})
	for a in MARKETING_ACTIVITIES:
		doc.append('activities', {'activity': a['activity'], 'cadence': a['cadence'],
			'kpi': a['kpi'], 'points': a['points']})
	doc.insert(ignore_permissions=True)


def seed_all():
	seed_content()
	seed_marketing_template()
